export function initializeDb() {
    return new Promise((resolve, reject) => {
        const request = indexedDB.open('SiteInspectorDb', 1);
        request.onupgradeneeded = (event) => {
            const db = event.target.result;
            if (!db.objectStoreNames.contains('inspections')) {
                const store = db.createObjectStore('inspections', { keyPath: 'id' });
                store.createIndex('syncStatus', 'syncStatus', { unique: false });
            }
        };
        request.onsuccess = () => {
            resolve(true);
        };
        request.onerror = () => reject(request.error);
    });
}

function getDb() {
    return new Promise((resolve, reject) => {
        const request = indexedDB.open('SiteInspectorDb', 1);
        request.onsuccess = () => resolve(request.result);
        request.onerror = () => reject(request.error);
    });
}

export async function saveInspection(inspection) {
    const db = await getDb();
    return new Promise((resolve, reject) => {
        const tx = db.transaction('inspections', 'readwrite');
        const store = tx.objectStore('inspections');
        store.put(inspection);
        tx.oncomplete = () => resolve(true);
        tx.onerror = () => reject(tx.error);
    });
}

export async function getAllInspections() {
    const db = await getDb();
    return new Promise((resolve, reject) => {
        const tx = db.transaction('inspections', 'readonly');
        const store = tx.objectStore('inspections');
        const request = store.getAll();
        request.onsuccess = () => resolve(request.result);
        request.onerror = () => reject(request.error);
    });
}

export async function getInspection(id) {
    const db = await getDb();
    return new Promise((resolve, reject) => {
        const tx = db.transaction('inspections', 'readonly');
        const store = tx.objectStore('inspections');
        const request = store.get(id);
        request.onsuccess = () => resolve(request.result || null);
        request.onerror = () => reject(request.error);
    });
}

export async function deleteInspection(id) {
    const db = await getDb();
    return new Promise((resolve, reject) => {
        const tx = db.transaction('inspections', 'readwrite');
        const store = tx.objectStore('inspections');
        store.delete(id);
        tx.oncomplete = () => resolve(true);
        tx.onerror = () => reject(tx.error);
    });
}

export async function getPendingInspections() {
    const db = await getDb();
    return new Promise((resolve, reject) => {
        const tx = db.transaction('inspections', 'readonly');
        const store = tx.objectStore('inspections');
        const index = store.index('syncStatus');
        const request = index.getAll(0); // 0 = Pending enum value
        request.onsuccess = () => resolve(request.result);
        request.onerror = () => reject(request.error);
    });
}

export async function updateSyncStatus(id, status) {
    const db = await getDb();
    return new Promise((resolve, reject) => {
        const tx = db.transaction('inspections', 'readwrite');
        const store = tx.objectStore('inspections');
        const getRequest = store.get(id);
        getRequest.onsuccess = () => {
            const inspection = getRequest.result;
            if (inspection) {
                inspection.syncStatus = status;
                store.put(inspection);
            }
            tx.oncomplete = () => resolve(true);
        };
        tx.onerror = () => reject(tx.error);
    });
}

let dotnetHelper = null;

export function isOnline() {
    return navigator.onLine;
}

export function registerOnlineHandler(helper) {
    dotnetHelper = helper;

    window.addEventListener('online', () => {
        if (dotnetHelper) {
