using Microsoft.JSInterop;
using SiteInspector.Models;
using System.Text.Json;

namespace SiteInspector.Services;

public class IndexedDbService
{
    private readonly IJSRuntime _jsRuntime;
    private IJSObjectReference? _module;
    private static readonly JsonSerializerOptions JsonOptions = new()
    {
        PropertyNamingPolicy = JsonNamingPolicy.CamelCase
    };

    public IndexedDbService(IJSRuntime jsRuntime)
    {
        _jsRuntime = jsRuntime;
    }

    private async Task<IJSObjectReference> GetModuleAsync()
    {
        _module ??= await _jsRuntime.InvokeAsync<IJSObjectReference>("import", "./js/indexedDb.js");
        return _module;
    }

    public async Task InitializeAsync()
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync("initializeDb");
    }

    public async Task SaveInspectionAsync(InspectionReport inspection)
    {
        var module = await GetModuleAsync();
        var json = JsonSerializer.Serialize(inspection, JsonOptions);
        var element = JsonSerializer.Deserialize<JsonElement>(json);
        await module.InvokeVoidAsync("saveInspection", element);
    }

    public async Task<List<InspectionReport>> GetAllInspectionsAsync()
    {
        var module = await GetModuleAsync();
        var result = await module.InvokeAsync<JsonElement>("getAllInspections");
        var json = result.GetRawText();
        return JsonSerializer.Deserialize<List<InspectionReport>>(json, JsonOptions) ?? new();
    }

    public async Task<InspectionReport?> GetInspectionAsync(Guid id)
    {
        var module = await GetModuleAsync();
        var result = await module.InvokeAsync<JsonElement?>("getInspection", id.ToString());
        if (result == null || result.Value.ValueKind == JsonValueKind.Null)
            return null;
        var json = result.Value.GetRawText();
        return JsonSerializer.Deserialize<InspectionReport>(json, JsonOptions);
    }

    public async Task DeleteInspectionAsync(Guid id)
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync("deleteInspection", id.ToString());
    }

    public async Task<List<InspectionReport>> GetPendingInspectionsAsync()
    {
        var module = await GetModuleAsync();
        var result = await module.InvokeAsync<JsonElement>("getPendingInspections");
        var json = result.GetRawText();
        return JsonSerializer.Deserialize<List<InspectionReport>>(json, JsonOptions) ?? new();
    }

    public async Task UpdateSyncStatusAsync(Guid id, SyncStatus status)
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync("updateSyncStatus", id.ToString(), (int)status);
    }
}

using Microsoft.JSInterop;

namespace SiteInspector.Services;

public class ConnectivityService : IDisposable
{
    private readonly IJSRuntime _jsRuntime;
    private IJSObjectReference? _module;
    private DotNetObjectReference<ConnectivityService>? _dotNetRef;

    public bool IsOnline { get; private set; } = true;
    public event Action<bool>? ConnectivityChanged;

    public ConnectivityService(IJSRuntime jsRuntime)
    {
        _jsRuntime = jsRuntime;
    }

    public async Task InitializeAsync()
    {
        _module = await _jsRuntime.InvokeAsync<IJSObjectReference>("import", "./js/connectivity.js");
        _dotNetRef = DotNetObjectReference.Create(this);
        IsOnline = await _module.InvokeAsync<bool>("registerOnlineHandler", _dotNetRef);
    }

    [JSInvokable]
    public void OnConnectivityChanged(bool isOnline)
    {
        IsOnline = isOnline;
        ConnectivityChanged?.Invoke(isOnline);
    }

    public void Dispose()
    {
        _dotNetRef?.Dispose();
    }
}

using SiteInspector.Models;
using System.Net.Http.Json;

namespace SiteInspector.Services;

public class SyncService : IDisposable
{
    private readonly IndexedDbService _dbService;
    private readonly ConnectivityService _connectivityService;
    private readonly HttpClient _httpClient;
    private Timer? _timer;

    public int PendingCount { get; private set; }
    public event Action? SyncStateChanged;

    public SyncService(IndexedDbService dbService, ConnectivityService connectivityService, HttpClient httpClient)
    {
        _dbService = dbService;
        _connectivityService = connectivityService;
        _httpClient = httpClient;
    }

    public async Task InitializeAsync()
    {
        _connectivityService.ConnectivityChanged += OnConnectivityChanged;
        await UpdatePendingCount();
        StartTimer();
    }

    private void StartTimer()
    {
        _timer = new Timer(async _ => await TrySyncAsync(), null, TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(30));
    }

    private async void OnConnectivityChanged(bool isOnline)
    {
        if (isOnline)
        {
            await TrySyncAsync();
        }
    }

    public async Task TrySyncAsync()
    {
        if (!_connectivityService.IsOnline)
            return;

        try
        {
            var pending = await _dbService.GetPendingInspectionsAsync();
            foreach (var inspection in pending)
            {
                try
                {
                    var response = await _httpClient.PostAsJsonAsync("/api/inspections", inspection);
                    if (response.IsSuccessStatusCode)
                    {
                        await _dbService.UpdateSyncStatusAsync(inspection.Id, SyncStatus.Synced);
                    }
                    else
                    {
                        await _dbService.UpdateSyncStatusAsync(inspection.Id, SyncStatus.Failed);
                    }
                }
                catch
                {
                    await _dbService.UpdateSyncStatusAsync(inspection.Id, SyncStatus.Failed);
                }
            }
        }
        catch
        {
            // Silently fail — will retry on next timer tick
        }

        await UpdatePendingCount();
        SyncStateChanged?.Invoke();
    }

    private async Task UpdatePendingCount()
    {
        try
        {
            var pending = await _dbService.GetPendingInspectionsAsync();
            PendingCount = pending.Count;
        }
        catch
        {
            // DB not ready yet
        }
    }

    public void Dispose()
    {
        _timer?.Dispose();
        _connectivityService.ConnectivityChanged -= OnConnectivityChanged;
    }
}

