@page "/inspection/new"
@inject IndexedDbService DbService
@inject NavigationManager Navigation
@inject IJSRuntime JS

<div class="page-new-inspection">
    <h2>New Inspection</h2>

    <div class="form-group">
        <label for="siteName">Site Name</label>
        <input id="siteName" type="text" @bind="_report.SiteName" @bind:event="oninput" placeholder="Enter site name" />
    </div>

    <div class="form-group">
        <label for="inspectorName">Inspector Name</label>
        <input id="inspectorName" type="text" @bind="_report.InspectorName" @bind:event="oninput" placeholder="Enter your name" />
    </div>

    <h3>Safety Checklist</h3>

    @foreach (var category in _categories)
    {
        <div class="checklist-category">
            <h4 class="category-title">@category</h4>
            @foreach (var item in _report.ChecklistItems.Where(i => i.Category == category))
            {
                <div class="checklist-item @(item.IsChecked ? "checked" : "")" @onclick="() => ToggleItem(item)">
                    <div class="check-indicator">
                        @if (item.IsChecked)
                        {
                            <span class="check-mark">✓</span>
                        }
                    </div>
                    <div class="item-content">
                        <span class="item-description">@item.Description</span>
                        @if (_expandedItemId == item.Id)
                        {
                            <div class="item-notes" @onclick:stopPropagation="true">
                                <input type="text" @bind="item.Notes" @bind:event="oninput" placeholder="Add notes..." />
                            </div>
                        }
                    </div>
                    <button class="notes-toggle" @onclick="() => ToggleNotes(item.Id)" @onclick:stopPropagation="true">
                        📝
                    </button>
                </div>
            }
        </div>
    }

    <div class="form-group">
        <label for="generalNotes">General Notes</label>
        <textarea id="generalNotes" @bind="_report.Notes" @bind:event="oninput" placeholder="Additional observations..." rows="4"></textarea>
    </div>

    <div class="photo-section">
        <h3>Photos</h3>
        <label class="btn-secondary photo-btn">
            📷 Capture Photo
            <InputFile OnChange="HandlePhotoSelected" accept="image/*" capture="environment" style="display:none" />
        </label>

        @if (_report.Photos.Count > 0)
        {
            <div class="photo-grid">
                @foreach (var photo in _report.Photos)
                {
                    <div class="photo-thumb">
                        <img src="data:image/jpeg;base64,@photo.Base64Data" alt="@photo.FileName" />
                        <button class="photo-remove" @onclick="() => RemovePhoto(photo)">✕</button>
                    </div>
                }
            </div>
        }
    </div>

    <button class="btn-primary btn-save" @onclick="SaveInspection" disabled="@(!CanSave)">
        Save Inspection
    </button>
</div>

@code {
    private InspectionReport _report = new()
    {
        ChecklistItems = DefaultChecklist.GetItems()
    };

    private List<string> _categories = new() { "Fall Protection", "Electrical Safety", "Scaffolding", "PPE Compliance", "Housekeeping" };
    private Guid? _expandedItemId;

    private bool CanSave => !string.IsNullOrWhiteSpace(_report.SiteName) && !string.IsNullOrWhiteSpace(_report.InspectorName);

    private void ToggleItem(ChecklistItem item)
    {
        item.IsChecked = !item.IsChecked;
    }

    private void ToggleNotes(Guid itemId)
    {
        _expandedItemId = _expandedItemId == itemId ? null : itemId;
    }

    private async Task HandlePhotoSelected(InputFileChangeEventArgs e)
    {
        foreach (var file in e.GetMultipleFiles(5))
        {
            if (file.Size > 10 * 1024 * 1024) continue; // Skip files > 10MB

            using var stream = file.OpenReadStream(10 * 1024 * 1024);
            using var ms = new System.IO.MemoryStream();
            await stream.CopyToAsync(ms);
            var base64 = Convert.ToBase64String(ms.ToArray());

            _report.Photos.Add(new InspectionPhoto
            {
                FileName = file.Name,
                Base64Data = base64,
                CapturedAt = DateTime.UtcNow
            });
        }
    }

    private void RemovePhoto(InspectionPhoto photo)
    {
        _report.Photos.Remove(photo);
    }

    private async Task SaveInspection()
    {
        if (!CanSave) return;

        _report.CreatedAt = DateTime.UtcNow;
        _report.SyncStatus = SyncStatus.Pending;

        await DbService.SaveInspectionAsync(_report);
        Navigation.NavigateTo("/");
    }
}

@page "/inspection/{Id:guid}"
@inject IndexedDbService DbService
@inject NavigationManager Navigation

<div class="page-inspection-detail">
    @if (_report == null)
    {
        <p class="loading-text">Loading...</p>
    }
    else
    {
        <div class="detail-header">
            <button class="btn-back" @onclick="GoBack">← Back</button>
            <span class="status-badge @_report.SyncStatus.ToString().ToLower()">@_report.SyncStatus</span>
        </div>

        <h2>@_report.SiteName</h2>
        <p class="detail-meta">
            <span>Inspector: @_report.InspectorName</span>
            <span>@_report.CreatedAt.ToString("MMM dd, yyyy HH:mm")</span>
        </p>

        @if (!string.IsNullOrWhiteSpace(_report.Notes))
        {
            <div class="detail-section">
                <h3>General Notes</h3>
                <p>@_report.Notes</p>
            </div>
        }

        <div class="detail-section">
            <h3>Checklist</h3>
            @foreach (var category in _report.ChecklistItems.Select(i => i.Category).Distinct())
            {
                <h4 class="category-title">@category</h4>
                @foreach (var item in _report.ChecklistItems.Where(i => i.Category == category))
                {
                    <div class="detail-checklist-item @(item.IsChecked ? "checked" : "unchecked")">
                        <span class="detail-check">@(item.IsChecked ? "✓" : "✗")</span>
                        <span class="detail-desc">@item.Description</span>
                        @if (!string.IsNullOrWhiteSpace(item.Notes))
                        {
                            <span class="detail-item-notes">— @item.Notes</span>
                        }
                    </div>
                }
            }
        </div>

        @if (_report.Photos.Count > 0)
        {
            <div class="detail-section">
                <h3>Photos (@_report.Photos.Count)</h3>
                <div class="photo-grid">
                    @foreach (var photo in _report.Photos)
                    {
                        <div class="photo-detail">
                            <img src="data:image/jpeg;base64,@photo.Base64Data" alt="@photo.FileName" />
                            <span class="photo-caption">@photo.FileName — @photo.CapturedAt.ToString("HH:mm")</span>
                        </div>
                    }
                </div>
            </div>
        }
    }
</div>

@code {
    [Parameter]
    public Guid Id { get; set; }

    private InspectionReport? _report;

    protected override async Task OnInitializedAsync()
    {
        _report = await DbService.GetInspectionAsync(Id);
    }

    private void GoBack()
    {
        Navigation.NavigateTo("/");
    }
}

@page "/sync"
@inject SyncService Sync
@inject ConnectivityService Connectivity
@inject IndexedDbService DbService
@implements IDisposable

<div class="page-sync">
    <h2>Sync Status</h2>

    <div class="sync-status-card">
        <div class="connectivity-status">
            <span class="connectivity-dot @(Connectivity.IsOnline ? "online" : "offline")"></span>
            <span>@(Connectivity.IsOnline ? "Online" : "Offline")</span>
        </div>
        <p class="pending-count">@Sync.PendingCount pending inspection(s)</p>
        <button class="btn-primary" @onclick="ManualSync" disabled="@(!Connectivity.IsOnline || _syncing)">
            @(_syncing ? "Syncing..." : "Sync Now")
        </button>
    </div>

    @if (_inspections != null)
    {
        <h3>All Inspections</h3>
        <div class="inspection-list">
            @foreach (var inspection in _inspections.OrderByDescending(i => i.CreatedAt))
            {
                <div class="inspection-card">
                    <div class="inspection-card-header">
                        <span class="site-name">@inspection.SiteName</span>
                        <span class="status-badge @inspection.SyncStatus.ToString().ToLower()">
                            @inspection.SyncStatus
                        </span>
                    </div>
                    <div class="inspection-card-body">
                        <span class="inspection-date">@inspection.CreatedAt.ToString("MMM dd, yyyy HH:mm")</span>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    private List<InspectionReport>? _inspections;
    private bool _syncing;

    protected override async Task OnInitializedAsync()
    {
        Sync.SyncStateChanged += OnSyncStateChanged;
        await LoadInspections();
    }

    private async Task LoadInspections()
    {
        _inspections = await DbService.GetAllInspectionsAsync();
    }

    private async Task ManualSync()
    {
        _syncing = true;
        StateHasChanged();

        await Sync.TrySyncAsync();
        await LoadInspections();

        _syncing = false;
        StateHasChanged();
    }

    private async void OnSyncStateChanged()
    {
        await InvokeAsync(async () =>
        {
            await LoadInspections();
            StateHasChanged();
        });
    }

    public void Dispose()
    {
        Sync.SyncStateChanged -= OnSyncStateChanged;
    }
}

