    text-transform: uppercase;
}
.status-badge.synced { background: #d4efdf; color: #1e8449; }
.status-badge.pending { background: #fdebd0; color: #b7950b; }
.status-badge.failed { background: #fadbd8; color: #922b21; }

/* Home Page */
.page-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
