}

.inspection-list {
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.inspection-card {
    background: white;
    border-radius: var(--radius);
    padding: 16px;
    box-shadow: var(--shadow);
    cursor: pointer;
    transition: transform 0.1s, box-shadow 0.15s;
    touch-action: manipulation;
}
.inspection-card:active {
    transform: scale(0.98);
    box-shadow: 0 1px 4px rgba(0,0,0,0.12);
}

.inspection-card-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 8px;
}
.site-name { font-weight: 700; font-size: 1rem; }

.inspection-card-body {
    display: flex;
    justify-content: space-between;
    font-size: 0.85rem;
    color: var(--gray-600);
    margin-bottom: 4px;
}

.inspection-card-footer {
    display: flex;
    justify-content: space-between;
    font-size: 0.8rem;
    color: var(--gray-600);
    padding-top: 8px;
    border-top: 1px solid var(--gray-200);
}

/* Checklist */
.checklist-category {
    margin-bottom: 20px;
}
.category-title {
    color: var(--primary);
    font-weight: 700;
    padding: 8px 0;
    border-bottom: 2px solid var(--gray-200);
    margin-bottom: 8px;
}

.checklist-item {
    display: flex;
    align-items: center;
    min-height: 56px;
    padding: 12px;
    margin-bottom: 8px;
    background: white;
    border-radius: var(--radius);
    border: 2px solid var(--gray-200);
