    transition: border-color 0.15s, background 0.15s, transform 0.1s;
    touch-action: manipulation;
    user-select: none;
}
.checklist-item:active { transform: scale(0.98); }
.checklist-item.checked {
    border-color: var(--success);
    background: #f0fdf4;
}

.check-indicator {
    width: 32px;
    height: 32px;
    border-radius: 50%;
    border: 2px solid var(--gray-300);
    display: flex;
    align-items: center;
    justify-content: center;
    margin-right: 12px;
    flex-shrink: 0;
    transition: background 0.15s, border-color 0.15s;
}
.checklist-item.checked .check-indicator {
    background: var(--success);
    border-color: var(--success);
}
.check-mark {
    color: white;
    font-weight: 700;
    font-size: 1rem;
}

.item-content {
    flex: 1;
    min-width: 0;
}
.item-description {
    font-size: 0.95rem;
}
.item-notes {
    margin-top: 8px;
}
.item-notes input {
    width: 100%;
    padding: 8px;
    border: 1px solid var(--gray-300);
    border-radius: 8px;
    font-size: 0.85rem;
}

.notes-toggle {
    background: none;
    border: none;
    font-size: 1.2rem;
    padding: 8px;
    min-width: 44px;
    min-height: 44px;
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    opacity: 0.6;
    transition: opacity 0.15s;
}
.notes-toggle:hover { opacity: 1; }

/* Photos */
.photo-section { margin: 24px 0; }
.photo-btn { margin-bottom: 12px; }
.photo-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(100px, 1fr));
    gap: 8px;
}
.photo-thumb {
    position: relative;
    aspect-ratio: 1;
    border-radius: 8px;
    overflow: hidden;
}
.photo-thumb img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}
.photo-remove {
    position: absolute;
    top: 4px;
    right: 4px;
    width: 28px;
    height: 28px;
    border-radius: 50%;
    background: rgba(0,0,0,0.6);
    color: white;
    border: none;
    font-size: 0.9rem;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
}

.btn-save {
