    font-size: 0.85rem;
    color: var(--gray-600);
    margin-bottom: 16px;
}
.detail-section {
    margin-bottom: 24px;
}
.detail-checklist-item {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 10px 12px;
    margin-bottom: 4px;
    border-radius: 8px;
    font-size: 0.9rem;
}
.detail-checklist-item.checked { background: #f0fdf4; }
.detail-checklist-item.unchecked { background: #fef9e7; }
.detail-check { font-weight: 700; font-size: 1.1rem; }
.detail-checklist-item.checked .detail-check { color: var(--success); }
.detail-checklist-item.unchecked .detail-check { color: var(--warning); }
.detail-item-notes { color: var(--gray-600); font-style: italic; font-size: 0.85rem; }

.photo-detail {
    border-radius: 8px;
    overflow: hidden;
    background: white;
    box-shadow: var(--shadow);
}
.photo-detail img {
    width: 100%;
    max-height: 300px;
    object-fit: cover;
}
.photo-caption {
    display: block;
    padding: 8px;
    font-size: 0.8rem;
    color: var(--gray-600);
}

/* Sync Page */
.sync-status-card {
    background: white;
    padding: 24px;
    border-radius: var(--radius);
    box-shadow: var(--shadow);
    text-align: center;
    margin-bottom: 24px;
}
.connectivity-status {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    margin-bottom: 12px;
    font-weight: 600;
