}

/* Status Badges */
.status-badge {
    display: inline-block;
    padding: 4px 10px;
    border-radius: 20px;
    font-size: 0.75rem;
    font-weight: 700;
    text-transform: uppercase;
}
.status-badge.synced { background: #d4efdf; color: #1e8449; }
.status-badge.pending { background: #fdebd0; color: #b7950b; }
.status-badge.failed { background: #fadbd8; color: #922b21; }

/* Home Page */
.page-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 16px;
}

.empty-state {
    text-align: center;
    padding: 48px 16px;
    color: var(--gray-600);
}

.inspection-list {
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.inspection-card {
    background: white;
    border-radius: var(--radius);
    padding: 16px;
    box-shadow: var(--shadow);
    cursor: pointer;
    transition: transform 0.1s, box-shadow 0.15s;
    touch-action: manipulation;
}
.inspection-card:active {
    transform: scale(0.98);
    box-shadow: 0 1px 4px rgba(0,0,0,0.12);
}

.inspection-card-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 8px;
}
.site-name { font-weight: 700; font-size: 1rem; }

.inspection-card-body {
    display: flex;
    justify-content: space-between;
    font-size: 0.85rem;
    color: var(--gray-600);
    margin-bottom: 4px;
}

.inspection-card-footer {
    display: flex;
    justify-content: space-between;
    font-size: 0.8rem;
    color: var(--gray-600);
    padding-top: 8px;
    border-top: 1px solid var(--gray-200);
}

/* Checklist */
.checklist-category {
    margin-bottom: 20px;
}
.category-title {
    color: var(--primary);
    font-weight: 700;
    padding: 8px 0;
    border-bottom: 2px solid var(--gray-200);
    margin-bottom: 8px;
}

.checklist-item {
    display: flex;
    align-items: center;
    min-height: 56px;
    padding: 12px;
    margin-bottom: 8px;
    background: white;
    border-radius: var(--radius);
    border: 2px solid var(--gray-200);
    cursor: pointer;
    transition: border-color 0.15s, background 0.15s, transform 0.1s;
    touch-action: manipulation;
    user-select: none;
}
.checklist-item:active { transform: scale(0.98); }
.checklist-item.checked {
    border-color: var(--success);
    background: #f0fdf4;
}

.check-indicator {
    width: 32px;
    height: 32px;
    border-radius: 50%;
    border: 2px solid var(--gray-300);
    display: flex;
    align-items: center;
    justify-content: center;
    margin-right: 12px;
    flex-shrink: 0;
    transition: background 0.15s, border-color 0.15s;
}
.checklist-item.checked .check-indicator {
    background: var(--success);
    border-color: var(--success);
}
.check-mark {
    color: white;
    font-weight: 700;
    font-size: 1rem;
}

.item-content {
    flex: 1;
    min-width: 0;
}
.item-description {
    font-size: 0.95rem;
}
.item-notes {
    margin-top: 8px;
}
.item-notes input {
    width: 100%;
    padding: 8px;
    border: 1px solid var(--gray-300);
    border-radius: 8px;
    font-size: 0.85rem;
}

.notes-toggle {
    background: none;
    border: none;
    font-size: 1.2rem;
    padding: 8px;
    min-width: 44px;
    min-height: 44px;
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    opacity: 0.6;
    transition: opacity 0.15s;
}
.notes-toggle:hover { opacity: 1; }

/* Photos */
.photo-section { margin: 24px 0; }
.photo-btn { margin-bottom: 12px; }
.photo-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(100px, 1fr));
    gap: 8px;
}
.photo-thumb {
    position: relative;
    aspect-ratio: 1;
    border-radius: 8px;
    overflow: hidden;
}
.photo-thumb img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}
.photo-remove {
    position: absolute;
    top: 4px;
    right: 4px;
    width: 28px;
    height: 28px;
    border-radius: 50%;
    background: rgba(0,0,0,0.6);
    color: white;
    border: none;
    font-size: 0.9rem;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
}

.btn-save {
    width: 100%;
    margin-top: 24px;
}

/* Inspection Detail */
.page-inspection-detail { padding-bottom: 16px; }
.detail-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 12px;
}
.detail-meta {
    display: flex;
    justify-content: space-between;
    font-size: 0.85rem;
    color: var(--gray-600);
    margin-bottom: 16px;
}
.detail-section {
    margin-bottom: 24px;
}
.detail-checklist-item {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 10px 12px;
    margin-bottom: 4px;
    border-radius: 8px;
    font-size: 0.9rem;
}
.detail-checklist-item.checked { background: #f0fdf4; }
.detail-checklist-item.unchecked { background: #fef9e7; }
.detail-check { font-weight: 700; font-size: 1.1rem; }
.detail-checklist-item.checked .detail-check { color: var(--success); }
.detail-checklist-item.unchecked .detail-check { color: var(--warning); }
.detail-item-notes { color: var(--gray-600); font-style: italic; font-size: 0.85rem; }

.photo-detail {
    border-radius: 8px;
    overflow: hidden;
    background: white;
    box-shadow: var(--shadow);
}
.photo-detail img {
    width: 100%;
    max-height: 300px;
    object-fit: cover;
}
.photo-caption {
    display: block;
    padding: 8px;
    font-size: 0.8rem;
    color: var(--gray-600);
}

/* Sync Page */
.sync-status-card {
    background: white;
    padding: 24px;
    border-radius: var(--radius);
    box-shadow: var(--shadow);
    text-align: center;
    margin-bottom: 24px;
}
.connectivity-status {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    margin-bottom: 12px;
    font-weight: 600;
}
.pending-count {
    font-size: 1.1rem;
    margin-bottom: 16px;
}

/* Loading */
.loading-text {
    text-align: center;
    color: var(--gray-600);
    padding: 48px;
}

/* Blazor defaults */
#blazor-error-ui {
    color-scheme: light only;
    background: lightyellow;
    bottom: 0;
    box-shadow: 0 -1px 2px rgba(0, 0, 0, 0.2);
    display: none;
    left: 0;
    padding: 0.6rem 1.25rem 0.7rem 1.25rem;
    position: fixed;
    width: 100%;
    z-index: 1000;
}
#blazor-error-ui .dismiss {
    cursor: pointer;
    position: absolute;
    right: 0.75rem;
    top: 0.5rem;
}

.blazor-error-boundary {
    background: #b32121;
    padding: 1rem;
    color: white;
}
.blazor-error-boundary::after {
    content: "An error has occurred.";
}

.loading-progress {
    position: absolute;
    display: block;
    width: 8rem;
    height: 8rem;
    inset: 20vh 0 auto 0;
    margin: 0 auto;
}
.loading-progress circle {
    fill: none;
    stroke: #e0e0e0;
    stroke-width: 0.6rem;
    transform-origin: 50% 50%;
    transform: rotate(-90deg);
}
.loading-progress circle:last-child {
    stroke: var(--primary, #1a5276);
    stroke-dasharray: calc(3.141 * var(--blazor-load-percentage, 0%) * 0.8), 500%;
    transition: stroke-dasharray 0.05s ease-in-out;
}
.loading-progress-text {
    position: absolute;
    text-align: center;
    font-weight: bold;
    inset: calc(20vh + 3.25rem) 0 auto 0.2rem;
}
.loading-progress-text:after {
    content: var(--blazor-load-percentage-text, "Loading");
}

