1. @page "/inspection/new"
2. @inject IndexedDbService DbService
3. @inject NavigationManager Navigation
4. @inject IJSRuntime JS
5. 
6. <div class="page-new-inspection">
7.     <h2>New Inspection</h2>
8. 
9.     <div class="form-group">
10.         <label for="siteName">Site Name</label>
11.         <input id="siteName" type="text" @bind="_report.SiteName" @bind:event="oninput" placeholder="Enter site name" />
12.     </div>
13. 
14.     <div class="form-group">
15.         <label for="inspectorName">Inspector Name</label>
16.         <input id="inspectorName" type="text" @bind="_report.InspectorName" @bind:event="oninput" placeholder="Enter your name" />
17.     </div>
18. 
19.     <h3>Safety Checklist</h3>
20. 
21.     @foreach (var category in _categories)
22.     {
23.         <div class="checklist-category">
24.             <h4 class="category-title">@category</h4>
25.             @foreach (var item in _report.ChecklistItems.Where(i => i.Category == category))
26.             {
27.                 <div class="checklist-item @(item.IsChecked ? "checked" : "")" @onclick="() => ToggleItem(item)">
28.                     <div class="check-indicator">
29.                         @if (item.IsChecked)
30.                         {
31.                             <span class="check-mark">✓</span>
32.                         }
33.                     </div>
34.                     <div class="item-content">
35.                         <span class="item-description">@item.Description</span>
36.                         @if (_expandedItemId == item.Id)
37.                         {
38.                             <div class="item-notes" @onclick:stopPropagation="true">
39.                                 <input type="text" @bind="item.Notes" @bind:event="oninput" placeholder="Add notes..." />
40.                             </div>
41.                         }
42.                     </div>
43.                     <button class="notes-toggle" @onclick="() => ToggleNotes(item.Id)" @onclick:stopPropagation="true">
44.                         📝
45.                     </button>
46.                 </div>
47.             }
48.         </div>
49.     }
50. 
51.     <div class="form-group">
52.         <label for="generalNotes">General Notes</label>
53.         <textarea id="generalNotes" @bind="_report.Notes" @bind:event="oninput" placeholder="Additional observations..." rows="4"></textarea>
54.     </div>
55. 
56.     <div class="photo-section">
57.         <h3>Photos</h3>
58.         <label class="btn-secondary photo-btn">
59.             📷 Capture Photo
60.             <InputFile OnChange="HandlePhotoSelected" accept="image/*" capture="environment" style="display:none" />
61.         </label>
62. 
63.         @if (_report.Photos.Count > 0)
64.         {
65.             <div class="photo-grid">
66.                 @foreach (var photo in _report.Photos)
67.                 {
68.                     <div class="photo-thumb">
69.                         <img src="data:image/jpeg;base64,@photo.Base64Data" alt="@photo.FileName" />
70.                         <button class="photo-remove" @onclick="() => RemovePhoto(photo)">✕</button>
71.                     </div>
72.                 }
73.             </div>
74.         }
75.     </div>
76. 
77.     <button class="btn-primary btn-save" @onclick="SaveInspection" disabled="@(!CanSave)">
78.         Save Inspection
79.     </button>
80. </div>
81. 
82. @code {
83.     private InspectionReport _report = new()
84.     {
85.         ChecklistItems = DefaultChecklist.GetItems()
86.     };
87. 
88.     private List<string> _categories = new() { "Fall Protection", "Electrical Safety", "Scaffolding", "PPE Compliance", "Housekeeping" };
89.     private Guid? _expandedItemId;
90. 
91.     private bool CanSave => !string.IsNullOrWhiteSpace(_report.SiteName) && !string.IsNullOrWhiteSpace(_report.InspectorName);
92. 
93.     private void ToggleItem(ChecklistItem item)
94.     {
95.         item.IsChecked = !item.IsChecked;
96.     }
97. 
98.     private void ToggleNotes(Guid itemId)
99.     {
100.         _expandedItemId = _expandedItemId == itemId ? null : itemId;
101.     }
102. 
103.     private async Task HandlePhotoSelected(InputFileChangeEventArgs e)
104.     {
105.         foreach (var file in e.GetMultipleFiles(5))
106.         {
107.             if (file.Size > 10 * 1024 * 1024) continue; // Skip files > 10MB
108. 
109.             using var stream = file.OpenReadStream(10 * 1024 * 1024);
110.             using var ms = new System.IO.MemoryStream();
111.             await stream.CopyToAsync(ms);
112.             var base64 = Convert.ToBase64String(ms.ToArray());
113. 
114.             _report.Photos.Add(new InspectionPhoto
115.             {
116.                 FileName = file.Name,
117.                 Base64Data = base64,
118.                 CapturedAt = DateTime.UtcNow
119.             });
120.         }
121.     }
122. 
123.     private void RemovePhoto(InspectionPhoto photo)
124.     {
125.         _report.Photos.Remove(photo);
126.     }
127. 
128.     private async Task SaveInspection()
129.     {
130.         if (!CanSave) return;
131. 
132.         _report.CreatedAt = DateTime.UtcNow;
133.         _report.SyncStatus = Models.SyncStatus.Pending;
134. 
135.         await DbService.SaveInspectionAsync(_report);
136.         Navigation.NavigateTo("/");
137.     }
138. }
139.

